public static long solve(long[] prices, long[] strategy, long k) {
    long maxProfit = 0;
    long originalProfit = 0;

    // Calculate the original profit
    for (int i = 0; i < prices.length; i++) {
        originalProfit += strategy[i] * prices[i];
    }

    // Try to improve the profit by modifying at most one segment of k consecutive elements
    for (int i = 0; i <= prices.length - k; i++) {
        // Calculate the profit change if we modify the segment [i, i + k - 1]
        long profitChange = 0;

        // For the first k/2 elements, change from -1 to 0 (buying to holding)
        for (int j = 0; j < k / 2; j++) {
            profitChange += (0 - strategy[i + j]) * prices[i + j];
        }

        // For the next k/2 elements, change from 1 to 1 (no change) or from 0 to 1 (holding to selling)
        for (int j = k / 2; j < k; j++) {
            if (strategy[i + j] == 0) {
                profitChange += (1 - 0) * prices[i + j];
            }
        }

        // Update the maximum profit
        maxProfit = Math.max(maxProfit, originalProfit + profitChange);
    }

    return maxProfit;
}
